import{_ as a,c as e,o as r,a4 as t}from"./chunks/framework.nQaBHiNx.js";const m=JSON.parse('{"title":"第一章 计算机网络概论","description":"","frontmatter":{"permalink":"/basic/ruankao/software-designer/01-compute-network-basic.html"},"headers":[],"relativePath":"computer/ruankao/software-designer/01-第一章 计算机网络概论.md","filePath":"computer/ruankao/software-designer/01-第一章 计算机网络概论.md"}'),o={name:"computer/ruankao/software-designer/01-第一章 计算机网络概论.md"},h=t('<h1 id="第一章-计算机网络概论" tabindex="-1">第一章 计算机网络概论 <a class="header-anchor" href="#第一章-计算机网络概论" aria-label="Permalink to &quot;第一章 计算机网络概论&quot;">​</a></h1><h2 id="_1-1-计算机系统基础知识" tabindex="-1">1.1 计算机系统基础知识 <a class="header-anchor" href="#_1-1-计算机系统基础知识" aria-label="Permalink to &quot;1.1 计算机系统基础知识&quot;">​</a></h2><h3 id="_1-1-1-计算机系统硬件基本组成" tabindex="-1">1.1.1 计算机系统硬件基本组成 <a class="header-anchor" href="#_1-1-1-计算机系统硬件基本组成" aria-label="Permalink to &quot;1.1.1 计算机系统硬件基本组成&quot;">​</a></h3><p>计算机系统是由硬件和软件组成的，他们协同工作来运行程序。</p><p>计算机的基本硬件系统由运算器、控制器、存储器、输入设备和输出设备 5 大部件组成。</p><h3 id="_1-1-2-中央处理单元" tabindex="-1">1.1.2 中央处理单元 <a class="header-anchor" href="#_1-1-2-中央处理单元" aria-label="Permalink to &quot;1.1.2 中央处理单元&quot;">​</a></h3><p>中央处理单元是计算机系统的核心部件，它负责获取程序指令、对指令进行译码并加以执行。</p><h3 id="_1-1-3-数据表示" tabindex="-1">1.1.3 数据表示 <a class="header-anchor" href="#_1-1-3-数据表示" aria-label="Permalink to &quot;1.1.3 数据表示&quot;">​</a></h3><p>各种数值在计算机中表示的形式成为机器数，其特点是采用二进制计数制，数的符号用 0 和 1 表示，小数点则隐含，表示不占位置。机器数对应的实际数值称为数的真值。</p><h3 id="_1-1-4-校验码" tabindex="-1">1.1.4 校验码 <a class="header-anchor" href="#_1-1-4-校验码" aria-label="Permalink to &quot;1.1.4 校验码&quot;">​</a></h3><p>计算机系统运行，为了确保数据在传送过程中正确无误，一是提高硬件电路的可靠性，二是提高软件程序的校验能力，包括差错和纠错。通常使用校验码的方法来检测传送的数据是否出错。</p><h2 id="_1-2-计算机体系结构" tabindex="-1">1.2 计算机体系结构 <a class="header-anchor" href="#_1-2-计算机体系结构" aria-label="Permalink to &quot;1.2 计算机体系结构&quot;">​</a></h2><h3 id="_1-2-1-计算机体系结构的发展" tabindex="-1">1.2.1 计算机体系结构的发展 <a class="header-anchor" href="#_1-2-1-计算机体系结构的发展" aria-label="Permalink to &quot;1.2.1 计算机体系结构的发展&quot;">​</a></h3><h3 id="_1-2-2-存储系统" tabindex="-1">1.2.2 存储系统 <a class="header-anchor" href="#_1-2-2-存储系统" aria-label="Permalink to &quot;1.2.2 存储系统&quot;">​</a></h3><h2 id="_1-3-安全性、可靠性与系统性能评测基础知识" tabindex="-1">1.3 安全性、可靠性与系统性能评测基础知识 <a class="header-anchor" href="#_1-3-安全性、可靠性与系统性能评测基础知识" aria-label="Permalink to &quot;1.3 安全性、可靠性与系统性能评测基础知识&quot;">​</a></h2><h3 id="_1-3-1-计算机安全概述" tabindex="-1">1.3.1 计算机安全概述 <a class="header-anchor" href="#_1-3-1-计算机安全概述" aria-label="Permalink to &quot;1.3.1 计算机安全概述&quot;">​</a></h3><h3 id="_1-3-2-加密技术和认证技术" tabindex="-1">1.3.2 加密技术和认证技术 <a class="header-anchor" href="#_1-3-2-加密技术和认证技术" aria-label="Permalink to &quot;1.3.2 加密技术和认证技术&quot;">​</a></h3><h3 id="_1-3-3-计算机可靠性" tabindex="-1">1.3.3 计算机可靠性 <a class="header-anchor" href="#_1-3-3-计算机可靠性" aria-label="Permalink to &quot;1.3.3 计算机可靠性&quot;">​</a></h3><h3 id="_1-3-4-计算机系统的性能评价" tabindex="-1">1.3.4 计算机系统的性能评价 <a class="header-anchor" href="#_1-3-4-计算机系统的性能评价" aria-label="Permalink to &quot;1.3.4 计算机系统的性能评价&quot;">​</a></h3>',19),i=[h];function n(l,_,d,s,c,u){return r(),e("div",null,i)}const q=a(o,[["render",n]]);export{m as __pageData,q as default};
